  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="26" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">A Conta de Larry Williams em 1987 — a Trajetória Real que Traçou</text>
    <text x="20" y="46" fill="#a1a1aa" font-size="13" font-family="sans-serif">Forma baseada em números de marcos reportados · não é uma escala linear</text>
    <line x1="60" y1="320" x2="650" y2="320" stroke="#3f3f46" stroke-width="1" stroke-dasharray="4,4"/>
