    <polyline points="80,320 150,270 230,190 310,90 370,130 430,230 500,195 560,175 610,160" fill="none" stroke="#4ade80" stroke-width="3"/>
    <circle cx="80" cy="320" r="6" fill="#a1a1aa"/>
