    <circle cx="310" cy="90" r="6" fill="#4ade80"/>
    <text x="310" y="75" fill="#86efac" font-size="13" font-weight="700" font-family="sans-serif" text-anchor="middle">Pico: ~US$ 2,2 milhões</text>
    <circle cx="430" cy="230" r="6" fill="#f87171"/>
